const BATCH = 10;

function parseMeta(raw) {
  if (!raw) return {};
  try {
    return typeof raw === 'string' ? JSON.parse(raw) : raw;
  } catch {
    return {};
  }
}

const res = $input.first().json;
const rows = Array.isArray(res.values) ? res.values : [];
if (rows.length < 2) {
  return [{ json: { empty: true, message: 'content_drafts trống' } }];
}

const headers = rows[0].map((x) => String(x ?? '').trim().toLowerCase());
const out = [];

for (let i = 1; i < rows.length; i++) {
  const cells = rows[i];
  if (!cells?.some((c) => String(c ?? '').trim())) continue;

  const row = { sheet_row: i + 1 };
  headers.forEach((key, j) => {
    if (key) row[key] = cells[j] ?? '';
  });

  const status = String(row.status || '').trim().toLowerCase();
  const meta = parseMeta(row.meta);

  if (meta.outreach_created === true) continue;
  if (status !== 'draft' && status !== 'approved') continue;

  const title = String(row.title || '').trim();
  const hook = String(row.hook_line || '').trim();
  if (!title || !hook) continue;

  out.push({ json: row });
  if (out.length >= BATCH) break;
}

if (!out.length) {
  return [{ json: { empty: true, message: 'Không còn draft chờ outreach (status=draft, chưa outreach)' } }];
}

return out;

const data = $getWorkflowStaticData('global');
data.a4_stats = { outreach_ok: 0, l0_fail: 0, l1_fail: 0, parse_fail: 0 };
return $input.all();

const row = $('Loop Outreach Candidates').item?.json || $input.first().json;

const system = `Trợ lý Magnix — Value-First outreach. [/ghost] [/brief]
Chỉ trả JSON hợp lệ:
{"segment":"","variant_a_cold":"","variant_b_after_engagement":"","variant_c_follow_up":"","ghost_check_passed":true,"compliance_note":""}
- variant_a_cold: ≤3 dòng, ≤280 ký tự
- variant_b_after_engagement: ≤4 câu
- Cấm: "Trong kỷ nguyên số", "Hơn nữa", "Tóm lại", "cam kết", "Đừng bỏ lỡ"`;

const userPayload = JSON.stringify({
  segment: row.segment || 'general_inbound',
  pain: String(row.hook_line || '').slice(0, 500),
  lead_magnet_title: row.title,
  context: 'cold',
  channel: 'zalo',
  source_normalized_key: row.source_normalized_key,
});

try {
  if ($env.DEEPSEEK_API_KEY) {
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: $env.DEEPSEEK_API_URL || 'https://api.deepseek.com/chat/completions',
      headers: {
        Authorization: `Bearer ${$env.DEEPSEEK_API_KEY}`,
        'Content-Type': 'application/json',
      },
      body: {
        model: $env.DEEPSEEK_MODEL || 'deepseek-chat',
        temperature: 0.5,
        max_tokens: 1024,
        response_format: { type: 'json_object' },
        messages: [
          { role: 'system', content: system },
          { role: 'user', content: userPayload },
        ],
      },
      json: true,
    });
    return [{ json: res }];
  }

  if ($env.ANTHROPIC_API_KEY) {
    const model = $env.ANTHROPIC_DRAFT_MODEL || 'claude-sonnet-4-6';
    const res = await this.helpers.httpRequest({
      method: 'POST',
      url: 'https://api.anthropic.com/v1/messages',
      headers: {
        'x-api-key': $env.ANTHROPIC_API_KEY,
        'anthropic-version': '2023-06-01',
        'Content-Type': 'application/json',
      },
      body: {
        model,
        max_tokens: 1024,
        temperature: 0.5,
        system,
        messages: [{ role: 'user', content: userPayload }],
      },
      json: true,
    });
    return [{ json: res }];
  }

  throw new Error('Thiếu DEEPSEEK_API_KEY hoặc ANTHROPIC_API_KEY');
} catch (e) {
  return [{ json: { error: true, message: e.message } }];
}

function extractJsonString(raw) {
  if (raw == null) throw new Error('EMPTY_LLM_OUTPUT');
  const s = typeof raw === 'string' ? raw : JSON.stringify(raw);
  const fenced = s.match(/```(?:json)?\s*([\s\S]*?)```/i);
  return (fenced ? fenced[1] : s).trim();
}

const res = $input.first().json;
const raw =
  res.choices?.[0]?.message?.content ??
  res.content?.[0]?.text ??
  res.message?.content ??
  res;

try {
  const parsed = JSON.parse(extractJsonString(raw));
  const required = ['segment', 'variant_a_cold', 'variant_b_after_engagement', 'variant_c_follow_up'];
  for (const k of required) {
    if (!parsed[k] || !String(parsed[k]).trim()) throw new Error(`MISSING_${k.toUpperCase()}`);
  }
  return [{
    json: {
      ok: true,
      outreach: {
        segment: String(parsed.segment),
        variant_a_cold: String(parsed.variant_a_cold).slice(0, 500),
        variant_b_after_engagement: String(parsed.variant_b_after_engagement).slice(0, 1500),
        variant_c_follow_up: String(parsed.variant_c_follow_up).slice(0, 1000),
        ghost_check_passed: parsed.ghost_check_passed !== false,
        compliance_note: String(parsed.compliance_note || '').slice(0, 500),
      },
    },
  }];
} catch (e) {
  return [{ json: { ok: false, parse_error: e.message, raw_preview: String(raw).slice(0, 200) } }];
}

const FORBIDDEN = [
  /trong kỷ nguyên số/i,
  /hơn nữa/i,
  /tóm lại/i,
  /cam kết/i,
  /đừng bỏ lỡ/i,
  /rất vui được/i,
];

const item = $input.first().json;
if (!item.ok || !item.outreach) {
  return [{ json: { ...item, l0_pass: false, l1_pass: false } }];
}

const o = item.outreach;
const text = [o.variant_a_cold, o.variant_b_after_engagement, o.variant_c_follow_up].join('\n');

const l0_hits = FORBIDDEN.filter((re) => re.test(text)).map((re) => re.source);
const coldLines = o.variant_a_cold.split(/\n/).filter((l) => l.trim()).length;
const l1_pass = coldLines <= 3 && o.variant_a_cold.length <= 320;

if (l0_hits.length) {
  return [{ json: { ok: false, l0_pass: false, l1_pass, l0_hits, error: 'L0_FORBIDDEN' } }];
}
if (!l1_pass) {
  return [{ json: { ok: false, l0_pass: true, l1_pass: false, error: 'L1_LENGTH' } }];
}

return [{ json: { ...item, l0_pass: true, l1_pass: true, l0_hits: [] } }];

const source = $('Loop Outreach Candidates').item?.json || {};
const item = $input.first().json;

if (!item.ok || !item.outreach) {
  return [{ json: { ok: false, error: 'MERGE_SKIP', draft_sheet_row: source.sheet_row } }];
}

const o = item.outreach;
const meta = JSON.stringify({
  l0_hits: item.l0_hits || [],
  ghost_check_passed: o.ghost_check_passed,
  agent: 'agent-4',
  draft_sheet_row: source.sheet_row,
  created_at: new Date().toISOString(),
}).slice(0, 50000);

return [{
  json: {
    ok: true,
    source_normalized_key: source.source_normalized_key,
    draft_sheet_row: source.sheet_row,
    append_row: [
      String(source.source_normalized_key || ''),
      String(source.title || ''),
      String(o.segment || source.segment || ''),
      o.variant_a_cold,
      o.variant_b_after_engagement,
      o.variant_c_follow_up,
      o.ghost_check_passed ? 'true' : 'false',
      o.compliance_note,
      'draft',
      'false',
      new Date().toISOString(),
      'agent4_outreach',
      meta,
    ],
    draft_meta_patch: {
      outreach_created: true,
      outreach_status: 'draft',
      outreach_at: new Date().toISOString(),
    },
  },
}];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'outreach_queue';

const item = $input.first().json;
if (!item.ok || !item.append_row) {
  return [{ json: { ok: false, error: 'SKIP_APPEND' } }];
}

await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
  method: 'POST',
  url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!A:M`)}:append?valueInputOption=USER_ENTERED&insertDataOption=INSERT_ROWS`,
  body: { values: [item.append_row] },
  json: true,
});

const data = $getWorkflowStaticData('global');
if (!data.a4_stats) data.a4_stats = { outreach_ok: 0, outreach_fail: 0 };
data.a4_stats.outreach_ok += 1;

return [{ json: { ok: true, storage: 'outreach_queue', normalized_key: item.source_normalized_key } }];

const SHEET_ID = '1fYB4h_BTiKXa9O3lBah-tQonWpQOQMG2aSkSfPs6yU4';
const TAB = 'content_drafts';

const merge = $('Merge Outreach Row').item?.json || $input.first().json;
if (!merge.draft_sheet_row || !merge.draft_meta_patch) {
  return [{ json: { ok: false, skip: true } }];
}

const row = merge.draft_sheet_row;
let existing = {};
try {
  const getRes = await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
    method: 'GET',
    url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!N${row}`)}`,
    json: true,
  });
  const cell = getRes.values?.[0]?.[0];
  if (cell) existing = JSON.parse(cell);
} catch {
  existing = {};
}

const meta = JSON.stringify({ ...existing, ...merge.draft_meta_patch }).slice(0, 50000);

await this.helpers.httpRequestWithAuthentication.call(this, 'googleApi', {
  method: 'PUT',
  url: `https://sheets.googleapis.com/v4/spreadsheets/${SHEET_ID}/values/${encodeURIComponent(`${TAB}!N${row}`)}?valueInputOption=USER_ENTERED`,
  body: { values: [[meta]] },
  json: true,
});

return [{ json: { ok: true, draft_row_updated: row } }];

const data = $getWorkflowStaticData('global');
if (!data.a4_stats) data.a4_stats = {};
const j = $input.first().json;
if (j.error === 'L1_LENGTH') data.a4_stats.l1_fail = (data.a4_stats.l1_fail || 0) + 1;
else data.a4_stats.l0_fail = (data.a4_stats.l0_fail || 0) + 1;
return $input.all();

const data = $getWorkflowStaticData('global');
if (!data.a4_stats) data.a4_stats = {};
data.a4_stats.parse_fail = (data.a4_stats.parse_fail || 0) + 1;
return $input.all();

const data = $getWorkflowStaticData('global');
const stats = data.a4_stats || {};
return [{ json: {
  ok: true,
  workflow: 'outreach-queue',
  stats,
  batch_size: 10,
  hint: (stats.outreach_ok || 0) === 0 ? 'Không outreach mới — hết draft hoặc L0/L1 fail' : 'Set l3_approved=true trên Sheet trước khi gửi',
  finished_at: new Date().toISOString(),
}}];
